    it('should create git commits when called', () => {
      // Get current commit count
      const before = execSync('git rev-list --count HEAD', { 
        encoding: 'utf-8' 
      }).trim();

      // Create a temporary change
      execSync('echo "primitive test change" > /tmp/test_change.txt');
      execSync('git add /tmp/test_change.txt 2>/dev/null || true');

      // Try to commit (may fail if no changes)
      try {
        execSync('git commit -m "Primitive test commit" --quiet');

        const after = execSync('git rev-list --count HEAD', { 
          encoding: 'utf-8' 
        }).trim();

        // If commit succeeded, count should increase
        expect(parseInt(after)).toBeGreaterThanOrEqual(parseInt(before));
      } catch {
        // No changes to commit is acceptable
        expect(true).toBe(true);
      }
    });
  });

