/**
 * ============================================================================
 * TASK 6: Integration Engine
 * ============================================================================
 * Autonomous Recognition: Bridges Task 7 (CLI) with Tasks 1-4 (Primitives)
 * 
 * Purpose: Single entry point for CLI to execute workflow primitives
 * without knowing implementation details.
 * ============================================================================
 */

import { actions } from './actions';
import type { ActionResult } from './actions';

/**
 * Integration Engine
 * Connects CLI commands to workflow primitives
 */
export class WorkflowIntegrationEngine {
  private sessionId: string | null = null;
  private history: ActionResult[] = [];

  /**
   * Initialize session context
   * Used by CLI to establish workflow context
   */
  async initialize(id?: string): Promise<{ id: string }> {
    this.sessionId = id || `session-${Date.now()}`;
    const result = actions.init(this.sessionId);
    this.history.push(result);
    return { id: this.sessionId };
  }

  /**
   * Execute command primitives
   * CLI calls this for arbitrary command execution
   */
  async executeCommand(command: string): Promise<ActionResult> {
    const result = actions.execute(command);
    this.history.push(result);
    return result;
  }

  /**
   * Commit changes
   * CLI calls this after file modifications
   */
  async commitChanges(message: string): Promise<ActionResult> {
    const result = actions.commit(message);
    this.history.push(result);
    return result;
  }

  /**
   * Archive session
   * CLI calls this for state preservation
   */
  async archiveSession(): Promise<ActionResult> {
    const result = actions.archive();
    this.history.push(result);
    return result;
  }

  /**
   * Get execution history
   * CLI queries this for session trace
   */
  getHistory(): ActionResult[] {
    return [...this.history];
  }

  /**
   * Full lifecycle execution
   * CLI shortcut for: init → execute → commit → archive
   */
  async executeLifecycle(
    command: string,
    commitMessage: string
  ): Promise<{ results: ActionResult[]; sessionId: string }> {
    // STEP 1: Initialize
    await this.initialize();

    // STEP 2: Execute
    await this.executeCommand(command);

    // STEP 3: Commit
    await this.commitChanges(commitMessage);

    // STEP 4: Archive
    await this.archiveSession();

    return {
      results: this.history,
      sessionId: this.sessionId!
    };
  }
}

/**
 * Singleton instance for CLI usage
 */
export const workflowEngine = new WorkflowIntegrationEngine();

/**
 * Direct CLI interface
 * Functions exported for cli/execute.ts (Task 7)
 */
export const cliInterface = {
  run: async (command: string, message: string) => {
    return workflowEngine.executeLifecycle(command, message);
  },

  archive: async () => {
    return workflowEngine.archiveSession();
  },

  status: () => {
    return {
      sessionId: workflowEngine['sessionId'],
      historyLength: workflowEngine.getHistory().length
    };
  }
};
EOF

