/**
 * ============================================================================
 * TASK 6: Workflow Bridge
 * ============================================================================
 * Integrates Task 7 CLI (src/cli/execute.ts) with Tasks 1-4 primitives
 * 
 * Allows existing CLI to leverage workflow primitives:
 * - actions.init, actions.execute, actions.commit, actions.archive
 * - steps.standard, steps.createFile, steps.gitWorkflow
 * ============================================================================
 */

import { actions } from './actions';
import { steps } from './steps';
import type { ActionResult } from './actions';
import { IntegrationEngine } from '../tools/plugins/integration';

/**
 * Bridge class: Connects CLI to workflow primitives
 */
export class WorkflowBridge {
  private engine: IntegrationEngine;
  private sessionId: string;
  private workflowResults: ActionResult[] = [];

  constructor(sessionId?: string) {
    this.engine = new IntegrationEngine();
    this.sessionId = sessionId || `bridge-${Date.now()}`;
  }

  /**
   * Bridge method: archiveCompletedTasks
   * CLI calls this → Bridge uses primitive actions.archive
   */
  async archiveCompletedTasks(): Promise<{ archived: number }> {
    // Use workflow primitive instead of engine directly
    const result = actions.archive();
    this.workflowResults.push(result);

    return {
      archived: result.success ? 1 : 0
    };
  }

  /**
   * Bridge method: runStandardWorkflow
   * CLI can call this to execute full workflow via primitives
   */
  async runStandardWorkflow(
    command: string,
    commitMessage: string
  ): Promise<{ results: ActionResult[] }> {
    // Use workflow steps.standard
    const results = steps.standard(this.sessionId, command, commitMessage);
    this.workflowResults.push(...results);

    return { results };
  }

  /**
   * Bridge method: executeCommand
   * CLI uses primitive actions.execute
   */
  async executeCommand(cmd: string): Promise<ActionResult> {
    const result = actions.execute(cmd);
    this.workflowResults.push(result);
    return result;
  }

  /**
   * Bridge method: createFile
   * CLI uses primitive steps.createFile
   */
  async createFileWorkflow(
    filename: string,
    content: string,
    commitMessage: string
  ): Promise<ActionResult[]> {
    const results = steps.createFile(filename, content, commitMessage);
    this.workflowResults.push(...results);
    return results;
  }

  /**
   * Get accumulated workflow results
   */
  getWorkflowResults(): ActionResult[] {
    return [...this.workflowResults];
  }

  /**
   * Get session ID
   */
  getSessionId(): string {
    return this.sessionId;
  }
}

/**
 * Singleton for CLI usage
 */
export const workflowBridge = new WorkflowBridge();

/**
 * Extension to existing IntegrationEngine
 * Adds workflow primitive capabilities
 */
export function extendWithWorkflowPrimitives(
  engine: IntegrationEngine,
  sessionId?: string
): WorkflowBridge {
  return new WorkflowBridge(sessionId);
}
